import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import SubmitForm from './SubmitForm';

test('submits form when button is clicked', async () => {
  const user = userEvent.setup();
  const onSubmit = jest.fn();

  render(<SubmitForm onSubmit={onSubmit} />);

  await user.type(screen.getByLabelText(/email/i), 'dev@byteai.com');
  await user.click(screen.getByRole('button', { name: /submit/i }));

  expect(onSubmit).toHaveBeenCalledWith({ email: 'dev@byteai.com' });
});

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { SubscribeButton } from './SubscribeButton';

test('disables button and shows loading after click', async () => {
  const user = userEvent.setup();
  render(<SubscribeButton onSubscribe={jest.fn().mockResolvedValue(undefined)} />);

  await user.click(screen.getByRole('button', { name: /subscribe/i }));

  expect(screen.getByRole('button')).toBeDisabled();
  expect(await screen.findByText(/subscribed!/i)).toBeVisible();
});

import { renderHook, act, waitFor } from '@testing-library/react';
import { useCounter } from './useCounter';

// Pure function
test.each([
  [2, 3, 5],
  [-1, 1, 0],
])('add(%i, %i) === %i', (a, b, expected) => {
  expect(add(a, b)).toBe(expected);
});

// Custom hook
test('useCounter increments', () => {
  const { result } = renderHook(() => useCounter(0));
  act(() => result.current.increment());
  expect(result.current.count).toBe(1);
});

// checkout.integration.test.tsx
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { CartProvider } from '../context/CartContext';
import CheckoutFlow from '../components/CheckoutFlow';

global.fetch = jest.fn();

beforeEach(() => {
  jest.clearAllMocks();
  (fetch as jest.Mock).mockResolvedValue({
    ok: true,
    json: async () => ({ orderId: 'abc-123' }),
  });
});

it('submits cart and shows confirmation', async () => {
  render(
    <CartProvider initialItems={[{ id: 1, name: 'Pro Plan', qty: 1 }]}>
      <CheckoutFlow />
    </CartProvider>
  );

  fireEvent.click(screen.getByRole('button', { name: /confirm order/i }));

  await waitFor(() =>
    expect(screen.getByText('Order abc-123 confirmed')).toBeInTheDocument()
  );
  expect(fetch).toHaveBeenCalledWith('/api/orders', expect.objectContaining({ method: 'POST' }));
});

