// Fake timers + async: flush microtasks manually
test('debounced fetch fires after 300ms', async () => {
  jest.useFakeTimers();
  const spy = jest.spyOn(api, 'search').mockResolvedValue([]);
  render(<SearchBox />);
  userEvent.type(screen.getByRole('searchbox'), 'react');
  jest.advanceTimersByTime(300);
  await Promise.resolve(); // flush pending microtasks
  expect(spy).toHaveBeenCalledWith('react');
  jest.useRealTimers();
});

